// Interface
interface Flyable {
    void fly();
    default void land() { System.out.println("landing"); }
}

public class Duck extends Animal implements Flyable, Swimmable {
    @Override public void speak() { System.out.println("Quack"); }
    @Override public void fly()   { System.out.println("Flying"); }
}

abstract class Shape {
    abstract double area();          // abstracto — sin implementación
    void describe() {               // concreto — con implementación
        System.out.println("Area: " + area());
    }
}

